CREATE OR REPLACE FUNCTION OFSERM.SUB_EXPOSURES_INVESTMENTS_DATA_POP(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_SUB_EXPOSURES(N_MIS_DATE_SKEY,F_DRAWN_EXP_FLAG,F_ELIGIBILITY_FLAG,N_CAPITAL_UL,N_DM_MITIGANT_SKEY,N_EFFECTIVE_ASSET_CLASS_SKEY,N_EFFECTIVE_COUNTRY_SKEY,N_LGD_PERCENT,N_MTG_TREATMENT_TYPE_SKEY,N_NET_MITIGANT_VALUE,N_PD_PERCENT,N_EAD_PRE_MITIGATION,N_RISK_WEIGHT,N_RUN_SKEY,N_BASEL_ISSUER_TYPE_SKEY,V_EXPOSURE_TYPE,N_CAP_APPROACH_TYPE_SKEY,V_APPROACH_TYPE,N_ACCT_SKEY,N_MITIGANT_SKEY,F_EXP_DEFAULTED_FLAG,F_PAST_DUE_FLAG,N_BASEL_ASSET_CLASS_SKEY,N_BASEL_PROD_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_CCF_PERCENT,N_CCF_PERCENT_DRAWN,N_CUST_ANNUAL_SALES,N_EAD_PRE_MITIGATION_DRAWN,N_EFF_MATURITY,N_GAAP_SKEY,N_INSTR_OTH_VALUATION_ADJ_AMT,N_INSTR_VALUATION_ADJ_AMOUNT,N_MIN_HOLDING_PERIOD_EXP,N_ORIGINAL_ASSET_CLASS_SKEY,N_ORIGINAL_MATURITY_EXP,N_RESIDUAL_MATURITY_EXP,N_RUN_PARAMETER_SETUP_SKEY,N_RWA_UL_AMT,N_EAD_PRE_MITIGATION_UNDRAWN,V_ACCOUNT_POOL_ID,V_CCY_CODE,V_PRODUCT_BOOK_CODE,F_MITIGANT_SECURITIZED_FLAG,N_BASEL_ISSUER_RATING,N_HOLDING_PERIOD,N_MIN_HOLDING_PERIOD_MTG,N_MITIGANT_VALUE,N_REMARGIN_FREQUENCY_MTG,N_RESIDUAL_MATURITY_MTG,N_REVAL_FREQUENCY_MTG,N_STD_MITIGANT_TYPE_SKEY,N_VOLATILITY_HAIRCUT,V_ISSUER_CCY_CODE,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_DATES.N_DATE_SKEY),'Y','Y',CASE WHEN DIM_STD_MITIGANT_TYPE.v_std_mitigant_type_code = 'UNCOV' THEN FSI_CAP_INVESTMENT_EXPOSURES.n_pre_mitigation_capital_ul END,FSI_CAP_EXP_MITIGANT_MAPPING.n_mitigant_skey,FSI_CAP_INVESTMENT_EXPOSURES.N_BASEL_ASSET_CLASS_SKEY,CASE WHEN DIM_STD_MITIGANT_TYPE.v_std_mitigant_category IN ('GUAR','CRD') THEN FSI_CAP_MITIGANTS.N_COUNTRY_SKEY ELSE FSI_CAP_INVESTMENT_EXPOSURES.N_COUNTRY_SKEY END,FSI_CAP_MITIGANTS.n_lgd_percent,dim_mitigant_treatment_type.n_mtg_treatment_type_skey,COALESCE(FSI_CAP_MITIGANTS.N_MITIGANT_VALUE,0),CASE WHEN FSI_CAP_MITIGANTS.n_pd_percent < 0.0003 THEN 0 ELSE FSI_CAP_MITIGANTS.n_pd_percent END,COALESCE(FSI_CAP_INVESTMENT_EXPOSURES.n_pre_crm_post_vol_hc_ead , FSI_CAP_INVESTMENT_EXPOSURES.n_ead_pre_mitigation ),CASE WHEN DIM_STD_MITIGANT_TYPE.v_std_mitigant_type_code = 'UNCOV' THEN FSI_CAP_INVESTMENT_EXPOSURES.n_pre_mitigation_rw_ul ELSE FSI_CAP_MITIGANTS.n_risk_weight END,'870',case when DIM_STD_MITIGANT_TYPE.v_std_mitigant_type_code='UNCOV' then FSI_CAP_INVESTMENT_EXPOSURES.n_std_counterparty_type_skey else FSI_CAP_MITIGANTS.n_basel_issuer_type_skey end,'NON-SEC',to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE,to_char(FSI_CAP_EXP_MITIGANT_MAPPING.N_ACCT_SKEY),to_char(FSI_CAP_EXP_MITIGANT_MAPPING.N_MITIGANT_SKEY),FSI_CAP_INVESTMENT_EXPOSURES.F_EXP_DEFAULTED_FLAG,FSI_CAP_INVESTMENT_EXPOSURES.F_PAST_DUE_FLAG,to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_BASEL_ASSET_CLASS_SKEY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_BASEL_PROD_TYPE_SKEY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_CCF_PERCENT),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_CCF_PERCENT_DRAWN),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_CUST_ANNUAL_SALES),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_DRAWN_EAD_PRE_MITIGATION),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_EFF_MATURITY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_INSTR_OTH_VALUATION_ADJ_AMT),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_INSTR_VALUATION_ADJ_AMOUNT),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_MIN_HOLDING_PERIOD),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_ORIGINAL_ASSET_CLASS_SKEY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_ORIGINAL_MATURITY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_RESIDUAL_MATURITY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_PARAMETER_SETUP_SKEY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_RWA_UL_AMT),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_UNDRAWN_EAD_PRE_MITIGATION),FSI_CAP_INVESTMENT_EXPOSURES.V_ACCOUNT_POOL_ID,FSI_CAP_INVESTMENT_EXPOSURES.V_CCY_CODE,FSI_CAP_INVESTMENT_EXPOSURES.V_PRODUCT_BOOK_CODE,FSI_CAP_MITIGANTS.F_SECURITIZED_FLAG,to_char(FSI_CAP_MITIGANTS.N_BASEL_ISSUER_RATING),to_char(FSI_CAP_MITIGANTS.N_HOLDING_PERIOD),to_char(FSI_CAP_MITIGANTS.N_MIN_HOLDING_PERIOD),to_char(FSI_CAP_MITIGANTS.N_MITIGANT_VALUE),to_char(FSI_CAP_MITIGANTS.N_REMARGIN_FREQUENCY),to_char(FSI_CAP_MITIGANTS.N_RESIDUAL_MATURITY),to_char(FSI_CAP_MITIGANTS.N_REVAL_FREQUENCY),to_char(FSI_CAP_MITIGANTS.N_STD_MITIGANT_TYPE_SKEY),to_char(FSI_CAP_MITIGANTS.N_VOLATILITY_HAIRCUT),FSI_CAP_MITIGANTS.V_CCY_CODE,to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE FROM FSI_CAP_EXP_MITIGANT_MAPPING INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' AND FSI_CAP_EXP_MITIGANT_MAPPING.N_RUN_SKEY = '870' LEFT OUTER JOIN DIM_DATES ON DIM_DATES.N_DATE_SKEY = FSI_CAP_EXP_MITIGANT_MAPPING.N_MIS_DATE_SKEY AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') LEFT OUTER JOIN FSI_CAP_MITIGANTS ON FSI_CAP_EXP_MITIGANT_MAPPING.N_MIS_DATE_SKEY = FSI_CAP_MITIGANTS.N_MIS_DATE_SKEY AND FSI_CAP_MITIGANTS.N_RUN_SKEY = '870' AND FSI_CAP_EXP_MITIGANT_MAPPING.N_MITIGANT_SKEY = FSI_CAP_MITIGANTS.N_MITIGANT_SKEY LEFT OUTER JOIN DIM_STD_MITIGANT_TYPE ON DIM_STD_MITIGANT_TYPE.N_STD_MITIGANT_TYPE_SKEY = FSI_CAP_MITIGANTS.N_STD_MITIGANT_TYPE_SKEY INNER JOIN FSI_CAP_INVESTMENT_EXPOSURES ON FSI_CAP_EXP_MITIGANT_MAPPING.N_MIS_DATE_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_MIS_DATE_SKEY AND FSI_CAP_EXP_MITIGANT_MAPPING.N_RUN_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY AND FSI_CAP_EXP_MITIGANT_MAPPING.N_ACCT_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_ACCT_SKEY LEFT OUTER JOIN DIM_BASEL_PRODUCT_TYPE ON FSI_CAP_INVESTMENT_EXPOSURES.N_BASEL_PROD_TYPE_SKEY = DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY LEFT OUTER JOIN DIM_BASEL_METHODOLOGY ON FSI_CAP_INVESTMENT_EXPOSURES.N_BASEL_METHOD_SKEY = DIM_BASEL_METHODOLOGY.N_BASEL_METHOD_SKEY INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_CAP_RECORD_TYPE_SKEY INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_CAP_APPROACH_TYPE_SKEY LEFT OUTER JOIN dim_mitigant_treatment_type ON dim_mitigant_treatment_type.v_mtg_treatment_type_code = 'OTH' AND TO_DATE(to_date('20260331','YYYYMMDD')) BETWEEN COALESCE(DIM_MITIGANT_TREATMENT_TYPE.D_RECORD_START_DATE, TO_DATE(to_date('20260331','YYYYMMDD'))) AND COALESCE(DIM_MITIGANT_TREATMENT_TYPE.D_RECORD_END_DATE, TO_DATE(to_date('20260331','YYYYMMDD'))) WHERE ((1=1) AND ( FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'BNK_NON_SEC_EXP' OR FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'DRV_NON_SEC_EXP' OR FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'INV_NON_SEC_EXP' OR FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'SFT_NON_SEC_EXP' ) AND (9=9) AND (3=3)) AND FSI_CAP_INVESTMENT_EXPOSURES.N_STD_ACCT_HEAD_SKEY IS NULL AND COALESCE(FSI_CAP_MITIGANTS.F_DIL_RISK_MITIGANT_FLAG, 'N') <> 'Y' AND ( COALESCE(FSI_CAP_MITIGANTS.F_ELIGIBILITY_FLAG, 'Y') <> 'N' OR COALESCE(FSI_CAP_EXP_MITIGANT_MAPPING.F_ELIGIBILITY_FLAG, 'Y') <> 'N' ) AND FSI_CAP_INVESTMENT_EXPOSURES.V_RECORD_TYPE = 'INV_NON_SEC_EXP' AND FSI_CAP_MITIGANTS.V_RECORD_TYPE = 'MITIGANT' LOG ERRORS INTO FSI_CAP_SUB_EXPOSURES$ ('1776770200366_89871096_20260331_1_Job_cc780cbd18de47bdb10ff99f995efec3') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
